mapper.sql:
AND c.recycle = 0
and c.id = #{id}
and c.recycle = #{recycle}
and c.post_id = #{post_key} or p.title like concat('%',#{post_key},'%')
and c.user_id = #{user_key} or u.user_name like concat('%',#{user_key},'%')
and c.content like concat('%',#{content},'%')
and c.post_id = #{post_id}
and p.store_id = #{store_id}

    AND c.parent_id = 0


    and c.top_id = #{top_id} and c.parent_id != 0

mapper.select:
SELECT c.user_id, u.user_name, c.post_id, p.title, c.content, DATE_FORMAT( c.create_time, '%Y-%m-%d %H:%i:%s' ) AS create_time, c.id, c.like_num, u.headimgurl, parent_user.user_name as parent_user_name, parent_user.headimgurl as parent_headimgurl, parent.content as parent_content FROM lkt_bbs_post_comment c INNER JOIN lkt_user u ON c.user_id = u.user_id INNER JOIN lkt_bbs_post p ON p.id = c.post_id LEFT JOIN lkt_bbs_post_comment parent ON c.parent_id = parent.id -- 自连接获取上级评论 LEFT JOIN lkt_user parent_user ON parent.user_id = parent_user.user_id -- 获取上级评论者用户名
ORDER BY c.like_num DESC, c.create_time DESC
limit #{pageNo},#{pageSize}

SELECT u.user_name,u.user_id FROM lkt_bbs_post_comment c
INNER JOIN lkt_user u ON u.user_id = c.user_id
WHERE c.id = #{id}
